/**
 * engine.wasm-bridge.js — Production bridge for the real C++ WASM engine.
 *
 * Drop this file into public/ and update index.html:
 *   Replace:  <script src="engine.sim.js"></script>
 *   With:     <script src="engine.js"></script>         ← generated by emcc
 *             <script src="engine.wasm-bridge.js"></script>
 *
 * The AlgoEngine object exposed here is API-identical to engine.sim.js,
 * so the rest of the JS in index.html requires ZERO changes.
 */

const AlgoEngine = (() => {
  let Module = null;
  let ready  = false;

  const NAMES = [
    "Bubble Sort","Selection Sort","Insertion Sort",
    "Merge Sort","Quick Sort","Binary Search"
  ];

  // Initialise the WASM module
  AlgoEngineWASM().then(mod => {
    Module = mod;
    ready  = true;
    document.getElementById('wasm-status').innerHTML =
      '<div class="dot live"></div> WASM LIVE';
    document.getElementById('footer-engine').textContent = 'Engine: C++ WebAssembly';
    console.log('[AlgoEngine] C++ WASM module loaded ✓');
  });

  /**
   * run(algoId, inputArray, extra) → Step[]
   * Calls the C++ run_algorithm, retrieves the JSON step timeline,
   * parses it, and returns the same shape as the JS sim.
   */
  function run(algoId, inputArray, extra = 0) {
    if (!ready) {
      console.warn('[AlgoEngine] WASM not ready yet — falling back to empty steps');
      return [];
    }

    const jsonStr  = JSON.stringify(inputArray);

    // Allocate C string in WASM heap
    const len      = Module.lengthBytesUTF8(jsonStr) + 1;
    const ptr      = Module._malloc(len);
    Module.stringToUTF8(jsonStr, ptr, len);

    // Call C++ engine
    Module._run_algorithm(algoId, ptr, extra);
    Module._free(ptr);

    // Retrieve step timeline
    const stepsPtr  = Module._get_steps_json();
    const stepsJson = Module.UTF8ToString(stepsPtr);
    Module._free_result(stepsPtr);

    return JSON.parse(stepsJson);
  }

  /**
   * getHistory() → HistoryRow[]
   * Reads the SQLite history table from C++.
   */
  function getHistory() {
    if (!ready) return [];
    const ptr  = Module._get_history_json();
    const json = Module.UTF8ToString(ptr);
    Module._free_result(ptr);
    return JSON.parse(json);
  }

  return { run, getHistory, NAMES };
})();
